<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -DENABLE_TYPE_DISCOVERY=NO</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
